Value.Calculation:
Let([
	ts = GetAsTimestamp ( Get ( CurrentHostTimestamp ) ) ;
	d = GetAsDate ( ts ) ;
	t = GetAsTime ( ts )
] ;
	Year ( d ) & "-" & Right ( "0" & Month ( d ) ; 2 ) & "-" & Right ( "0" & Day ( d ) ; 2 ) & "T" &
	Right ( "0" & Hour ( t ) ; 2 ) & ":" & Right ( "0" & Minute ( t ) ; 2 ) & ":" & Right ( "0" & Int ( Seconds ( t ) ) ; 2 ) & "Z"
)

Let([
	url_norm = Lower ( TrimAll ( GetAsText ( $$SUPABASE_URL ) ; 1 ; 1 ) ) ;
	url_ok = url_norm = "https://pjwfrshrhikcubssytfw.supabase.co" or url_norm = "https://yiyiqinzdilnnqqrepkm.supabase.co" ;
	parse_err = If ( JSONGetElementType ( $json ; "" ) = JSONArray ; "" ; Left ( "JSON_PARSE_ERROR: " & $json ; 200 ) ) ;
	url_err = If ( url_ok ; "" ; "URL_NOT_ALLOWED: " & url_norm )
] ;
	List ( parse_err ; url_err )
)

Let([
	raw = TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].jahresraten" ) ) ; 1 ; 1 ) ;
	allowed = Filter ( raw ; "0123456789,.- " ) ;
	parse_ok = Length ( allowed ) = Length ( raw ) and not IsEmpty ( raw ) and raw ≠ "null" ;
	raw_dot = Substitute ( Substitute ( allowed ; " " ; "" ) ; "," ; "." ) ;
	n2 = GetAsNumber ( raw_dot )
] ; If ( parse_ok and Abs ( n2 ) < 10000000000 ; n2 ; "" ))

Let([
	raw = TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].kosten_pro_rate" ) ) ; 1 ; 1 ) ;
	allowed = Filter ( raw ; "0123456789,.- " ) ;
	parse_ok = Length ( allowed ) = Length ( raw ) and not IsEmpty ( raw ) and raw ≠ "null" ;
	raw_clean = Substitute ( Substitute ( allowed ; " " ; "" ) ; "," ; "." ) ;
	n = GetAsNumber ( raw_clean ) ;
	v = Case ( not parse_ok ; "" ; n > 1000 ; n / 100 ; n )
] ; If ( not IsEmpty ( v ) and Abs ( v ) < 10000000000 ; v ; "" ))

Let([
	raw = TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].kosten_jaehrlich" ) ) ; 1 ; 1 ) ;
	allowed = Filter ( raw ; "0123456789,.- " ) ;
	parse_ok = Length ( allowed ) = Length ( raw ) and not IsEmpty ( raw ) and raw ≠ "null" ;
	raw_clean = Substitute ( Substitute ( allowed ; " " ; "" ) ; "," ; "." ) ;
	n = GetAsNumber ( raw_clean ) ;
	v = Case ( not parse_ok ; "" ; n > 1000 ; n / 100 ; n )
] ; If ( not IsEmpty ( v ) and Abs ( v ) < 10000000000 ; v ; "" ))

Let([
	d_raw = TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].vertrags_datum" ) ) ; 1 ; 1 ) ;
	d_token = GetValue ( Substitute ( d_raw ; " " ; "¶" ) ; 1 ) ;
	d_clean = Substitute ( Substitute ( d_token ; Char(34) ; "" ) ; Char(92) ; "" )
] ; Case ( IsEmpty ( d_clean ) or Lower ( d_clean ) = "null" ; "" ; PatternCount ( d_clean ; "-" ) = 2 ; Left ( d_clean ; 10 ) ; "" ))

Let([
	d_raw = TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].vertrags_beginn" ) ) ; 1 ; 1 ) ;
	d_token = GetValue ( Substitute ( d_raw ; " " ; "¶" ) ; 1 ) ;
	d_clean = Substitute ( Substitute ( d_token ; Char(34) ; "" ) ; Char(92) ; "" )
] ; Case ( IsEmpty ( d_clean ) or Lower ( d_clean ) = "null" ; "" ; PatternCount ( d_clean ; "-" ) = 2 ; Left ( d_clean ; 10 ) ; "" ))

Let([
	d_raw = TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].vertrags_ablauf" ) ) ; 1 ; 1 ) ;
	d_token = GetValue ( Substitute ( d_raw ; " " ; "¶" ) ; 1 ) ;
	d_clean = Substitute ( Substitute ( d_token ; Char(34) ; "" ) ; Char(92) ; "" )
] ; Case ( IsEmpty ( d_clean ) or Lower ( d_clean ) = "null" ; "" ; PatternCount ( d_clean ; "-" ) = 2 ; Left ( d_clean ; 10 ) ; "" ))

JSONSetElement ( "{}" ;
[ "vertrag_id" ; JSONGetElement ( $json ; "[" & $idx & "].vertrag_id" ) ; JSONString ] ;
[ "vertragsbesitzer_id" ; $vertragsbesitzer_id_calc ; JSONString ] ;
[ "gruppe" ; JSONGetElement ( $json ; "[" & $idx & "].gruppe" ) ; JSONString ] ;
[ "untergruppe" ; JSONGetElement ( $json ; "[" & $idx & "].untergruppe" ) ; JSONString ] ;
[ "firma" ; JSONGetElement ( $json ; "[" & $idx & "].firma" ) ; JSONString ] ;
[ "kontakt" ; JSONGetElement ( $json ; "[" & $idx & "].kontakt" ) ; JSONString ] ;
[ "telefon" ; JSONGetElement ( $json ; "[" & $idx & "].telefon" ) ; JSONString ] ;
[ "mobil" ; JSONGetElement ( $json ; "[" & $idx & "].mobil" ) ; JSONString ] ;
[ "fax" ; JSONGetElement ( $json ; "[" & $idx & "].fax" ) ; JSONString ] ;
[ "email" ; JSONGetElement ( $json ; "[" & $idx & "].email" ) ; JSONString ] ;
[ "webseite" ; JSONGetElement ( $json ; "[" & $idx & "].webseite" ) ; JSONString ] ;
[ "zugang" ; $zugang_sync ; If ( IsEmpty ( TrimAll ( GetAsText ( $zugang_sync ) ; 1 ; 1 ) ) ; JSONNull ; JSONString ) ] ;
[ "passwort" ; $passwort_sync ; If ( IsEmpty ( TrimAll ( GetAsText ( $passwort_sync ) ; 1 ; 1 ) ) ; JSONNull ; JSONString ) ] ;
[ "diskret" ; If ( $diskret ; "x" ; "" ) ; If ( $diskret ; JSONString ; JSONNull ) ] ;
[ "beschreibung" ; JSONGetElement ( $json ; "[" & $idx & "].beschreibung" ) ; JSONString ] ;
[ "vertragsnummer" ; JSONGetElement ( $json ; "[" & $idx & "].vertragsnummer" ) ; JSONString ] ;
[ "iban" ; JSONGetElement ( $json ; "[" & $idx & "].iban" ) ; JSONString ] ;
[ "bic" ; JSONGetElement ( $json ; "[" & $idx & "].bic" ) ; JSONString ] ;
[ "bank" ; JSONGetElement ( $json ; "[" & $idx & "].bank" ) ; JSONString ] ;
[ "jahresraten" ; $jahresraten_val ; If ( IsEmpty ( $jahresraten_val ) ; JSONNull ; JSONNumber ) ] ;
[ "kosten_pro_rate" ; $kosten_pro_rate_val ; If ( IsEmpty ( $kosten_pro_rate_val ) ; JSONNull ; JSONNumber ) ] ;
[ "kosten_jaehrlich" ; $kosten_jaehrlich_val ; If ( IsEmpty ( $kosten_jaehrlich_val ) ; JSONNull ; JSONNumber ) ] ;
[ "zahlungsweise" ; JSONGetElement ( $json ; "[" & $idx & "].zahlungsweise" ) ; JSONString ] ;
[ "vertrags_datum" ; $d_vertrags_datum ; If ( IsEmpty ( $d_vertrags_datum ) ; JSONNull ; JSONString ) ] ;
[ "vertrags_beginn" ; $d_vertrags_beginn ; If ( IsEmpty ( $d_vertrags_beginn ) ; JSONNull ; JSONString ) ] ;
[ "vertrags_ablauf" ; $d_vertrags_ablauf ; If ( IsEmpty ( $d_vertrags_ablauf ) ; JSONNull ; JSONString ) ] ;
[ "datei_pfad_2" ; JSONGetElement ( $json ; "[" & $idx & "].logo" ) ; JSONString ] ;
[ "notizen" ; JSONGetElement ( $json ; "[" & $idx & "].vertrag" ) ; JSONString ] ;
[ "modified_by" ; "filemaker" ; JSONString ] ;
[ "sync_state" ; "geaendert" ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "script_name" ; "04_FM_ARCHIVY_SYNC_VERTRAEGE_PUSH_EXAKT" ; JSONString ] ;
	[ "script_version" ; $script_version ; JSONString ] ;
	[ "owner_id" ; Lower ( TrimAll ( GetAsText ( $$INHABER_ID ) ; 1 ; 1 ) ) ; JSONString ] ;
	[ "status" ; Case ( IsEmpty ( $fehler ) ; "ok" ; "error" ) ; JSONString ] ;
	[ "ok_count" ; $ok ; JSONNumber ] ;
	[ "skip_count" ; 0 ; JSONNumber ] ;
	[ "error_count" ; Case ( IsEmpty ( $fehler ) ; 0 ; ValueCount ( $fehler ) ) ; JSONNumber ] ;
	[ "result_text" ; Left ( $$SYNC_RESULT_V ; 9000 ) ; JSONString ] ;
	[ "error_text" ; Left ( $fehler ; 9000 ) ; JSONString ] ;
	[ "needs_review" ; True ; JSONBoolean ] ;
	[ "detail_json" ; JSONSetElement ( "{}" ;
		[ "processed_count" ; $anzahl ; JSONNumber ] ;
		[ "table" ; $$FM_VERTRAEGE_TABELLE ; JSONString ]
	) ; JSONObject ]
)
